import React from 'react';
import { TouchableOpacity, Text, ActivityIndicator, ViewStyle } from 'react-native';

interface AccessibleButtonProps {
  onPress: () => void;
  title: string;
  loading?: boolean;
  disabled?: boolean;
  accessibilityLabel?: string;
  accessibilityHint?: string;
  style?: ViewStyle;
}

const AccessibleButton: React.FC<AccessibleButtonProps> = ({
  onPress,
  title,
  loading = false,
  disabled = false,
  accessibilityLabel,
  accessibilityHint,
  style,
}) => {
  const finalLabel = accessibilityLabel || `Bouton ${title}`;
  const finalHint = accessibilityHint || `Appuyez deux fois pour ${title.toLowerCase()}`;

  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={disabled || loading}
      accessible={true}
      accessibilityLabel={finalLabel}
      accessibilityHint={finalHint}
      accessibilityRole="button"
      accessibilityState={{ disabled: disabled || loading, busy: loading }}
      style={[{ padding: 12, borderRadius: 8, backgroundColor: '#0066cc' }, style]}
    >
      {loading ? (
        <ActivityIndicator color="white" />
      ) : (
        <Text style={{ color: 'white', textAlign: 'center', fontSize: 16 }}>
          {title}
        </Text>
      )}
    </TouchableOpacity>
  );
};

export default AccessibleButton;
