import { useWindowDimensions, PixelRatio } from 'react-native';
import { useEffect, useState } from 'react';

const useDynamicFontSize = (baseSize: number): number => {
  const [fontScale, setFontScale] = useState(PixelRatio.getFontScale());
  const { fontScale: windowFontScale } = useWindowDimensions();

  useEffect(() => {
    setFontScale(PixelRatio.getFontScale());
  }, [windowFontScale]);

  // Limiter l'échelle maximale à 2 pour éviter les débordements
  const limitedScale = Math.min(fontScale, 2);
  return baseSize * limitedScale;
};

// Utilisation
const dynamicFontSize = useDynamicFontSize(14);
<Text style={{ fontSize: dynamicFontSize }}>Texte adaptatif</Text>
