import { useColorScheme } from 'react-native';
import { useEffect, useState } from 'react';

interface ColorPalette {
  background: string;
  textPrimary: string;
  textSecondary: string;
  buttonBackground: string;
  buttonText: string;
}

const lightTheme: ColorPalette = {
  background: '#FFFFFF',
  textPrimary: '#1A1A1A', // Contraste ~15:1
  textSecondary: '#595959', // Contraste ~8:1 (≥ 4.5)
  buttonBackground: '#0066CC',
  buttonText: '#FFFFFF',
};

const darkTheme: ColorPalette = {
  background: '#121212',
  textPrimary: '#FFFFFF',
  textSecondary: '#B3B3B3', // Contraste sur fond #121212 ~7.5:1
  buttonBackground: '#0A84FF',
  buttonText: '#FFFFFF',
};

const useAccessibleColors = (): ColorPalette => {
  const colorScheme = useColorScheme();
  const [colors, setColors] = useState(colorScheme === 'dark' ? darkTheme : lightTheme);

  useEffect(() => {
    setColors(colorScheme === 'dark' ? darkTheme : lightTheme);
  }, [colorScheme]);

  return colors;
};

export default useAccessibleColors;
